const COACH_DEFAULT = [
  { title: "Conseguir 5 contactos nuevos" },
  { title: "Rellamar 5 empresas" },
  { title: "Conseguir una reunión" }
];
const ESTADOS = ["Todos","Nuevo","Por contactar","Contactado","Cotizado","Seguimiento","Cliente"];
const PRIORIDADES = ["Alta","Media","Baja"];
const TIERS = [
  {min:0,label:"Explorador",emoji:"🧭"},
  {min:75,label:"Prospector",emoji:"📞"},
  {min:160,label:"Negociador",emoji:"🤝"},
  {min:280,label:"Cazador",emoji:"🎯"},
  {min:450,label:"Closer",emoji:"💼"},
  {min:700,label:"Maestro comercial",emoji:"👑"}
];

const $ = (id) => document.getElementById(id);
const state = {
  authMode: "login",
  session: null,
  user: null,
  profile: null,
  leads: [],
  tasks: [],
  coachTasks: [],
  selectedLeadId: null,
  activeTab: "inicio",
  filters: { query:"", provincia:"Todas", rubro:"Todos", estado:"Todos", soloPend:false, soloFav:false },
  modalMode: "create",
  editingId: null,
  channel: null
};

function esc(s) {
  return String(s ?? "")
    .replaceAll("&","&amp;")
    .replaceAll("<","&lt;")
    .replaceAll(">","&gt;")
    .replaceAll('"',"&quot;")
    .replaceAll("'","&#39;");
}

function showToast(msg) {
  const t = $("toast");
  t.textContent = msg;
  t.style.display = "block";
  clearTimeout(window.__toastTimer);
  window.__toastTimer = setTimeout(() => t.style.display = "none", 2800);
}

function todayStr() {
  return new Date().toISOString().slice(0,10);
}

function toDateStr(date) {
  return date.toISOString().slice(0,10);
}

function addBusinessDays(dateStr, days) {
  const d = new Date(dateStr + "T12:00:00");
  let added = 0;
  while (added < days) {
    d.setDate(d.getDate() + 1);
    const wd = d.getDay();
    if (wd !== 0 && wd !== 6) added++;
  }
  return toDateStr(d);
}

function diffDays(a, b) {
  if (!a || !b) return null;
  const da = new Date(a), dbb = new Date(b);
  if (Number.isNaN(da.getTime()) || Number.isNaN(dbb.getTime())) return null;
  return Math.floor((dbb - da) / 86400000);
}

function dueLevel(lead) {
  if (!lead.proximo_seguimiento) return "sin";
  const d = diffDays(lead.proximo_seguimiento, todayStr());
  if (d === null) return "sin";
  if (d > 0) return "vencido";
  if (d === 0) return "hoy";
  if (d >= -2) return "pronto";
  return "ok";
}

function dueBadge(lead) {
  const map = { vencido:"Vencido", hoy:"Hoy", pronto:"Pronto", ok:"OK", sin:"Sin fecha" };
  const cls = dueLevel(lead) === "vencido" ? "danger" : (dueLevel(lead) === "pronto" ? "warn" : "");
  return `<span class="badge ${cls}">${map[dueLevel(lead)]}</span>`;
}

function nextAction(lead) {
  const due = dueLevel(lead);
  if (!lead.telefono) return "Conseguir teléfono y validar contacto comercial.";
  if (due === "vencido") return "Recontactar hoy mismo y registrar el resultado.";
  if (lead.estado === "Nuevo") return "Primer contacto breve con foco en detectar operación actual.";
  if (lead.estado === "Contactado") return "Mandar propuesta concreta o pedir detalles del próximo embarque.";
  if (lead.estado === "Cotizado") return "Retomar con argumento de cierre y alternativa logística.";
  if (lead.estado === "Seguimiento") return "Mantener presencia con novedad útil y próxima fecha.";
  return "Actualizar ficha y definir siguiente paso.";
}

function taskReward(lead) {
  let r = 15;
  if (lead.telefono) r += 5;
  if (lead.contacto) r += 5;
  if ((lead.score || 0) >= 70) r += 10;
  if (lead.prioridad === "Alta") r += 10;
  if (dueLevel(lead) === "vencido") r += 5;
  return r;
}

function currentTier() {
  return [...TIERS].reverse().find(t => (state.profile?.xp || 0) >= t.min) || TIERS[0];
}

function nextTier() {
  return TIERS.find(t => t.min > (state.profile?.xp || 0)) || null;
}

function taskIdForLead(lead) {
  return `${lead.id}::${lead.task_version || 1}`;
}

function selectedLead() {
  return state.leads.find(l => l.id === state.selectedLeadId) || null;
}

function metrics() {
  return {
    due: state.leads.filter(l => ["vencido","hoy"].includes(dueLevel(l))).length,
    withoutPhone: state.leads.filter(l => !l.telefono).length,
    highPriority: state.leads.filter(l => l.prioridad === "Alta").length,
    contacted: state.leads.filter(l => ["Contactado","Cotizado","Seguimiento","Cliente"].includes(l.estado)).length
  };
}

function smartQueue() {
  return [...state.leads]
    .map(l => ({
      ...l,
      urgency:
        (dueLevel(l) === "vencido" ? 50 : 0) +
        (dueLevel(l) === "hoy" ? 35 : 0) +
        (!l.telefono ? 20 : 0) +
        (l.prioridad === "Alta" ? 20 : 0) +
        ((l.score || 0) / 10)
    }))
    .sort((a,b) => b.urgency - a.urgency)
    .slice(0,20);
}

function filteredLeadsBase() {
  const q = state.filters.query.toLowerCase().trim();
  return state.leads.filter(l => {
    const matchesQuery = !q || [l.empresa,l.rubro,l.provincia,l.telefono,l.origen_habitual,l.tipo_operaciones,l.localidad,l.contacto]
      .filter(Boolean).some(v => String(v).toLowerCase().includes(q));
    const matchesProv = state.filters.provincia === "Todas" || l.provincia === state.filters.provincia;
    const matchesRubro = state.filters.rubro === "Todos" || l.rubro === state.filters.rubro;
    const matchesEstado = state.filters.estado === "Todos" || l.estado === state.filters.estado;
    const matchesPend = !state.filters.soloPend || ["vencido","hoy","pronto"].includes(dueLevel(l));
    const matchesFav = !state.filters.soloFav || !!l.favorita;
    return matchesQuery && matchesProv && matchesRubro && matchesEstado && matchesPend && matchesFav;
  });
}

function filteredLeads() {
  let arr = filteredLeadsBase();
  const mode = window.__metricMode || "";
  if (mode === "withoutPhone") arr = arr.filter(l => !l.telefono);
  if (mode === "highPriority") arr = arr.filter(l => l.prioridad === "Alta");
  if (mode === "contacted") arr = arr.filter(l => ["Contactado","Cotizado","Seguimiento","Cliente"].includes(l.estado));
  return arr;
}

function rotatingTips() {
  const slot = Math.floor(Date.now() / (30 * 60 * 1000));
  const idx = slot % SALES_TIPS.length;
  const picks = [];
  for (let i = 0; i < 4; i++) picks.push(SALES_TIPS[(idx + i) % SALES_TIPS.length]);
  return picks;
}

function levelTrackHtml() {
  return TIERS.map(t => `<span class="level-pill">${t.emoji} ${t.label}</span>`).join("");
}

function playSuccessSound() {
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    const o1 = ctx.createOscillator();
    const o2 = ctx.createOscillator();
    const g = ctx.createGain();
    o1.type = "sine"; o2.type = "triangle";
    o1.frequency.value = 880; o2.frequency.value = 1320;
    g.gain.setValueAtTime(.001, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(.12, ctx.currentTime + .02);
    g.gain.exponentialRampToValueAtTime(.001, ctx.currentTime + .22);
    o1.connect(g); o2.connect(g); g.connect(ctx.destination);
    o1.start(); o2.start(ctx.currentTime + .04);
    o1.stop(ctx.currentTime + .18); o2.stop(ctx.currentTime + .22);
  } catch (e) {}
}

async function updateProfile(patch) {
  if (!state.user) return;
  const updateData = { id: state.user.id, ...patch };
  const { error } = await db.from("profiles").upsert(updateData);
  if (error) {
    console.error(error);
    showToast("No pude actualizar el perfil.");
  }
}

async function fetchAllData() {
  await ensureTodayCoachTasks();
  const [profileRes, leadsRes, tasksRes, coachRes] = await Promise.all([
    db.from("profiles").select("*").eq("id", state.user.id).single(),
    db.from("leads").select("*").order("created_at", { ascending: false }),
    db.from("tasks").select("*").eq("completed", false).order("due_date", { ascending: true, nullsFirst: false }),
    db.from("coach_tasks").select("*").eq("task_date", todayStr()).order("created_at", { ascending: true })
  ]);
  if (profileRes.error) console.error(profileRes.error);
  if (leadsRes.error) console.error(leadsRes.error);
  if (tasksRes.error) console.error(tasksRes.error);
  if (coachRes.error) console.error(coachRes.error);
  state.profile = profileRes.data || { xp:0, streak:0, display_name: state.user.email };
  state.leads = leadsRes.data || [];
  state.tasks = tasksRes.data || [];
  state.coachTasks = coachRes.data || [];
  if (!state.selectedLeadId || !state.leads.some(l => l.id === state.selectedLeadId)) {
    state.selectedLeadId = state.leads[0]?.id || null;
  }
  render();
}

async function ensureProfile() {
  const { data } = await db.from("profiles").select("*").eq("id", state.user.id).maybeSingle();
  if (!data) {
    const displayName = state.user.user_metadata?.display_name || state.user.email?.split("@")[0] || "Usuario";
    await db.from("profiles").upsert({ id: state.user.id, email: state.user.email, display_name: displayName });
  }
}

async function ensureTodayCoachTasks() {
  const { data, error } = await db.from("coach_tasks").select("id").eq("task_date", todayStr()).limit(1);
  if (error) {
    console.error(error);
    return;
  }
  if (!data || !data.length) {
    const rows = COACH_DEFAULT.map(t => ({
      user_id: state.user.id,
      task_date: todayStr(),
      title: t.title,
      done: false
    }));
    const ins = await db.from("coach_tasks").insert(rows);
    if (ins.error) console.error(ins.error);
  }
}

async function maybeResetStreakByMissedDays() {
  if (!state.profile) return;
  const last = state.profile.last_task_completed_on;
  if (!last) return;
  const gap = diffDays(last, todayStr());
  if (gap !== null && gap > 1 && state.profile.streak !== 0) {
    await updateProfile({ streak: 0 });
  }
}

async function syncInitialImportIfEmpty() {
  const { count, error } = await db.from("leads").select("*", { count: "exact", head: true });
  if (error) {
    console.error(error);
    return;
  }
  if ((count || 0) === 0) {
    const batch = INITIAL_IMPORT.slice(0, 400).map(row => ({
      ...row,
      user_id: state.user.id
    }));
    const res = await db.from("leads").insert(batch);
    if (res.error) console.error(res.error);
  }
}

async function signup() {
  const email = $("authEmail").value.trim();
  const password = $("authPassword").value;
  const displayName = $("signupName").value.trim();
  if (!email || !password || !displayName) return showToast("Completá email, contraseña y nombre.");
  const { error } = await db.auth.signUp({
    email,
    password,
    options: {
      data: { display_name: displayName }
    }
  });
  if (error) return showToast(error.message);
  showToast("Cuenta creada. Ahora ingresá con tu email y contraseña.");
  switchAuthMode("login");
}

async function login() {
  const email = $("authEmail").value.trim();
  const password = $("authPassword").value;
  if (!email || !password) return showToast("Completá email y contraseña.");
  const { error } = await db.auth.signInWithPassword({ email, password });
  if (error) return showToast(error.message);
}

async function logout() {
  await db.auth.signOut();
}

function switchAuthMode(mode) {
  state.authMode = mode;
  $("authTitle").textContent = mode === "login" ? "Ingresar" : "Crear cuenta";
  $("signupNameWrap").classList.toggle("hidden", mode === "login");
  $("authPrimaryBtn").textContent = mode === "login" ? "Entrar" : "Crear cuenta";
  $("authSwitchBtn").textContent = mode === "login" ? "Crear cuenta" : "Ya tengo cuenta";
}

async function handleAuth(session) {
  if (session?.user) {
    state.session = session;
    state.user = session.user;
    $("loginView").classList.add("hidden");
    $("appView").classList.remove("hidden");
    await ensureProfile();
    await maybeResetStreakByMissedDays();
    await syncInitialImportIfEmpty();
    await fetchAllData();
    subscribeRealtime();
  } else {
    state.session = null;
    state.user = null;
    if (state.channel) {
      db.removeChannel(state.channel);
      state.channel = null;
    }
    $("appView").classList.add("hidden");
    $("loginView").classList.remove("hidden");
  }
}

function subscribeRealtime() {
  if (state.channel) return;
  state.channel = db.channel("crm-sync")
    .on("postgres_changes", { event: "*", schema: "public", table: "leads", filter: `user_id=eq.${state.user.id}` }, fetchAllData)
    .on("postgres_changes", { event: "*", schema: "public", table: "tasks", filter: `user_id=eq.${state.user.id}` }, fetchAllData)
    .on("postgres_changes", { event: "*", schema: "public", table: "coach_tasks", filter: `user_id=eq.${state.user.id}` }, fetchAllData)
    .on("postgres_changes", { event: "*", schema: "public", table: "profiles", filter: `id=eq.${state.user.id}` }, fetchAllData)
    .subscribe();
}

async function patchLead(id, patch) {
  const { error } = await db.from("leads").update(patch).eq("id", id);
  if (error) {
    console.error(error);
    showToast("No pude actualizar el lead.");
  }
}

async function completeLeadTask(id) {
  const lead = state.leads.find(l => l.id === id);
  if (!lead) return;
  const currentTaskId = taskIdForLead(lead);
  if (lead.last_rewarded_task_id === currentTaskId) {
    showToast("Esa tarea ya fue completada. Ya no da recompensas.");
    return;
  }
  const pts = taskReward(lead);
  const nextDate = addBusinessDays(todayStr(), 15);

  let nextStreak = state.profile?.streak || 0;
  const lastDone = state.profile?.last_task_completed_on;
  if (!lastDone) {
    nextStreak = 1;
  } else {
    const gap = diffDays(lastDone, todayStr());
    if (gap === 0) {
      nextStreak = state.profile?.streak || 1;
    } else if (gap === 1) {
      nextStreak = (state.profile?.streak || 0) + 1;
    } else {
      nextStreak = 1;
    }
  }

  const leadUpdate = await db.from("leads").update({
    ultimo_contacto: todayStr(),
    proximo_seguimiento: nextDate,
    estado: lead.estado === "Nuevo" ? "Contactado" : lead.estado,
    last_rewarded_task_id: currentTaskId,
    task_version: (lead.task_version || 1) + 1
  }).eq("id", id);

  if (leadUpdate.error) {
    console.error(leadUpdate.error);
    return showToast("No pude completar la gestión.");
  }

  const taskInsert = await db.from("tasks").insert({
    user_id: state.user.id,
    lead_id: lead.id,
    title: `Recontactar a ${lead.empresa}`,
    due_date: nextDate,
    notes: nextAction(lead),
    source: "gestion"
  });
  if (taskInsert.error) console.error(taskInsert.error);

  await updateProfile({
    xp: (state.profile?.xp || 0) + pts,
    streak: nextStreak,
    last_task_completed_on: todayStr()
  });

  playSuccessSound();
  if ("Notification" in window && Notification.permission === "granted") {
    new Notification("Gestión completada", { body: `${lead.empresa}: +${pts} XP. Nueva tarea para ${nextDate}.` });
  }
  showToast(`Gestión completada. +${pts} XP. Nueva tarea para ${nextDate}.`);
  await fetchAllData();
}
window.completeLeadTask = completeLeadTask;

function openLeadFromOutside(id) {
  state.selectedLeadId = id;
  state.activeTab = "leads";
  render();
}
window.openLeadFromOutside = openLeadFromOutside;

async function toggleCoachTask(id, done) {
  const { error } = await db.from("coach_tasks").update({ done }).eq("id", id);
  if (error) {
    console.error(error);
    showToast("No pude actualizar el coach.");
  }
}

async function createManualTask() {
  const title = $("taskTitleInput").value.trim();
  const dueDate = $("taskDateInput").value;
  const notes = $("taskNoteInput").value.trim();
  if (!title) return showToast("La tarea necesita un título.");
  const { error } = await db.from("tasks").insert({
    user_id: state.user.id,
    title,
    due_date: dueDate || null,
    notes,
    source: "manual"
  });
  if (error) {
    console.error(error);
    return showToast("No pude crear la tarea.");
  }
  $("taskTitleInput").value = "";
  $("taskDateInput").value = "";
  $("taskNoteInput").value = "";
  showToast("Tarea creada.");
}
window.createManualTask = createManualTask;

async function completeTaskItem(id) {
  const { error } = await db.from("tasks").update({ completed: true, completed_at: new Date().toISOString() }).eq("id", id);
  if (error) {
    console.error(error);
    return showToast("No pude completar la tarea.");
  }
  showToast("Tarea completada.");
}
window.completeTaskItem = completeTaskItem;

async function deleteTaskItem(id) {
  const { error } = await db.from("tasks").delete().eq("id", id);
  if (error) {
    console.error(error);
    return showToast("No pude borrar la tarea.");
  }
}
window.deleteTaskItem = deleteTaskItem;

function exportExcel() {
  const data = state.leads.map(l => ({
    Empresa:l.empresa, Contacto:l.contacto, "Teléfono":l.telefono, Email:l.email, Provincia:l.provincia,
    Localidad:l.localidad, Rubro:l.rubro, Web:l.web, "Dirección":l.direccion, "Origen habitual":l.origen_habitual,
    "Tipo operaciones":l.tipo_operaciones, Tamaño:l.tamano, Estado:l.estado, Prioridad:l.prioridad, Score:l.score,
    "Último contacto":l.ultimo_contacto, "Próximo seguimiento":l.proximo_seguimiento, Notas:l.notas
  }));
  const ws = XLSX.utils.json_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "CRM");
  XLSX.writeFile(wb, `CRM_Prospectos_${(state.profile?.display_name || "usuario").replaceAll(" ","_")}.xlsx`);
  showToast("Excel exportado.");
}

async function importExcel(file) {
  const reader = new FileReader();
  reader.onload = async (e) => {
    const data = new Uint8Array(e.target.result);
    const wb = XLSX.read(data, { type: "array" });
    const ws = wb.Sheets[wb.SheetNames[0]];
    const rows = XLSX.utils.sheet_to_json(ws, { defval: "" });
    const mapped = rows.map((x) => ({
      user_id: state.user.id,
      empresa: String(x.Empresa || x.empresa || "").trim(),
      contacto: String(x.Contacto || x.contacto || "").trim(),
      telefono: String(x["Teléfono"] || x.telefono || x.Telefono || "").trim(),
      email: String(x.Email || x.email || "").trim(),
      provincia: String(x.Provincia || x.provincia || "Sin dato").trim(),
      localidad: String(x.Localidad || x.localidad || "").trim(),
      rubro: String(x.Rubro || x.rubro || "Sin clasificar").trim(),
      web: String(x.Web || x.web || "").trim(),
      direccion: String(x["Dirección"] || x.direccion || x.Direccion || "").trim(),
      origen_habitual: String(x["Origen habitual"] || x.origen_habitual || "").trim(),
      tipo_operaciones: String(x["Tipo operaciones"] || x.tipo_operaciones || "").trim(),
      tamano: String(x.Tamaño || x.tamano || x.Tamano || "Sin dato").trim(),
      estado: String(x.Estado || x.estado || "Nuevo").trim(),
      prioridad: String(x.Prioridad || x.prioridad || "Media").trim(),
      score: Number(x.Score || x.score || 0),
      ultimo_contacto: String(x["Último contacto"] || x.ultimo_contacto || "").trim() || null,
      proximo_seguimiento: String(x["Próximo seguimiento"] || x.proximo_seguimiento || "").trim() || null,
      notas: String(x.Notas || x.notas || "").trim(),
      favorita: false,
      task_version: 1,
      last_rewarded_task_id: ""
    })).filter(x => x.empresa);

    if (!mapped.length) return showToast("No encontré filas válidas.");
    const { error } = await db.from("leads").insert(mapped);
    if (error) {
      console.error(error);
      return showToast("No pude importar el Excel.");
    }
    showToast(`Se importaron ${mapped.length} contactos.`);
  };
  reader.readAsArrayBuffer(file);
}

async function saveModal() {
  const payload = {
    empresa: $("mEmpresa").value.trim(),
    contacto: $("mContacto").value.trim(),
    telefono: $("mTelefono").value.trim(),
    email: $("mEmail").value.trim(),
    provincia: $("mProvincia").value.trim(),
    localidad: $("mLocalidad").value.trim(),
    rubro: $("mRubro").value.trim(),
    web: $("mWeb").value.trim(),
    direccion: $("mDireccion").value.trim(),
    origen_habitual: $("mOrigen").value.trim(),
    tipo_operaciones: $("mTipo").value.trim(),
    tamano: $("mTamano").value.trim() || "Sin dato",
    estado: $("mEstado").value,
    prioridad: $("mPrioridad").value,
    score: Number($("mScore").value || 0),
    favorita: $("mFav").checked,
    ultimo_contacto: $("mUltimo").value || null,
    proximo_seguimiento: $("mProximo").value || null,
    notas: $("mNotas").value.trim()
  };
  if (!payload.empresa) return showToast("La empresa es obligatoria.");

  if (state.modalMode === "create") {
    const { error } = await db.from("leads").insert({ user_id: state.user.id, ...payload });
    if (error) {
      console.error(error);
      return showToast("No pude crear el lead.");
    }
  } else {
    const { error } = await db.from("leads").update(payload).eq("id", state.editingId);
    if (error) {
      console.error(error);
      return showToast("No pude actualizar el lead.");
    }
  }
  $("modalBg").style.display = "none";
  showToast("Lead guardado.");
}

function openModal(mode) {
  state.modalMode = mode;
  const lead = mode === "edit" ? selectedLead() : null;
  state.editingId = lead?.id || null;
  $("modalTitle").textContent = mode === "create" ? "Nuevo contacto" : "Editar contacto";
  $("modalSub").textContent = mode === "create" ? "Cargá un lead nuevo" : "Modificá la ficha seleccionada";

  const src = lead || {
    empresa:"", contacto:"", telefono:"", email:"", provincia:"", localidad:"", rubro:"", web:"",
    direccion:"", origen_habitual:"", tipo_operaciones:"", tamano:"", estado:"Nuevo", prioridad:"Media",
    score:0, favorita:false, ultimo_contacto:"", proximo_seguimiento:"", notas:""
  };
  const set = (id,val) => $(id).value = val ?? "";
  set("mEmpresa", src.empresa);
  set("mContacto", src.contacto);
  set("mTelefono", src.telefono);
  set("mEmail", src.email);
  set("mProvincia", src.provincia);
  set("mLocalidad", src.localidad);
  set("mRubro", src.rubro);
  set("mWeb", src.web);
  set("mDireccion", src.direccion);
  set("mOrigen", src.origen_habitual);
  set("mTipo", src.tipo_operaciones);
  set("mTamano", src.tamano);
  set("mScore", src.score || 0);
  set("mUltimo", src.ultimo_contacto || "");
  set("mProximo", src.proximo_seguimiento || "");
  set("mNotas", src.notas);
  $("mEstado").innerHTML = ESTADOS.slice(1).map(o => `<option value="${esc(o)}" ${src.estado===o?'selected':''}>${esc(o)}</option>`).join("");
  $("mPrioridad").innerHTML = PRIORIDADES.map(o => `<option value="${esc(o)}" ${src.prioridad===o?'selected':''}>${esc(o)}</option>`).join("");
  $("mFav").checked = !!src.favorita;
  $("modalBg").style.display = "grid";
}

async function deleteSelectedLead() {
  const lead = selectedLead();
  if (!lead) return;
  if (!confirm(`¿Querés borrar a ${lead.empresa}?`)) return;
  const { error } = await db.from("leads").delete().eq("id", lead.id);
  if (error) {
    console.error(error);
    return showToast("No pude borrar el lead.");
  }
  showToast("Lead eliminado.");
}

async function toggleFavoriteSelected() {
  const lead = selectedLead();
  if (!lead) return;
  await patchLead(lead.id, { favorita: !lead.favorita });
}

function applyMetricFilter(metric) {
  state.activeTab = "leads";
  state.filters = { query:"", provincia:"Todas", rubro:"Todos", estado:"Todos", soloPend:false, soloFav:false };
  window.__metricMode = metric;
  if (metric === "due") {
    state.filters.soloPend = true;
    window.__metricMode = "";
  }
  render();
}

function render() {
  $("headerSub").textContent = `${state.leads.length} leads · Usuario: ${state.profile?.display_name || state.user?.email || ""}`;
  const m = metrics();
  $("metricDue").textContent = m.due;
  $("metricPhone").textContent = m.withoutPhone;
  $("metricPriority").textContent = m.highPriority;
  $("metricContacted").textContent = m.contacted;

  const ct = currentTier(), nt = nextTier();
  $("tierEmoji").textContent = ct.emoji;
  $("tierLabel").textContent = ct.label;
  $("pointsValue").textContent = state.profile?.xp || 0;
  $("streakValue").textContent = state.profile?.streak || 0;
  const progress = nt ? Math.max(0, Math.min(100, (((state.profile?.xp || 0) - ct.min) / (nt.min - ct.min)) * 100)) : 100;
  $("progressBar").style.width = `${progress}%`;
  $("progressText").textContent = nt ? `Te faltan ${nt.min - (state.profile?.xp || 0)} XP para llegar a ${nt.label}.` : "Ya estás en el nivel más alto.";
  $("levelTrack").innerHTML = levelTrackHtml();

  const motivationIndex = (Math.floor(Date.now() / (30*60*1000)) + (state.profile?.xp || 0) + (state.profile?.streak || 0)) % MOTIVATIONS.length;
  $("motivationBox").textContent = MOTIVATIONS[motivationIndex];

  const provs = ["Todas", ...new Set(state.leads.map(l => l.provincia).filter(Boolean))];
  const rubs = ["Todos", ...new Set(state.leads.map(l => l.rubro).filter(Boolean))];
  const options = (arr,val) => arr.map(o => `<option value="${esc(o)}" ${o===val?'selected':''}>${esc(o)}</option>`).join("");
  $("filterProvincia").innerHTML = options(provs, state.filters.provincia);
  $("filterRubro").innerHTML = options(rubs, state.filters.rubro);
  $("filterEstado").innerHTML = options(ESTADOS, state.filters.estado);
  $("searchInput").value = state.filters.query;
  $("filterPend").checked = state.filters.soloPend;
  $("filterFav").checked = state.filters.soloFav;

  const leads = filteredLeads();
  $("filteredCountTitle").textContent = `Leads filtrados (${leads.length})`;
  $("leadList").innerHTML = leads.length ? leads.map(l => `
    <button class="lead-item ${l.id===state.selectedLeadId?'selected':''}" data-lead-id="${l.id}">
      <div class="row between">
        <div>
          <div><strong>${esc(l.empresa || "Sin empresa")}</strong></div>
          <div class="muted">${esc(l.rubro || "")} · ${esc(l.provincia || "")}</div>
        </div>
        ${dueBadge(l)}
      </div>
      <div class="row" style="margin-top:10px">
        <span class="badge">${esc(l.estado || "Nuevo")}</span>
        <span class="badge">${esc(l.prioridad || "Media")}</span>
        <span class="badge">Score ${l.score || 0}</span>
        ${l.favorita ? '<span class="badge">⭐ Favorito</span>' : ''}
      </div>
    </button>
  `).join("") : `<div class="empty">No hay resultados con esos filtros.</div>`;
  document.querySelectorAll("[data-lead-id]").forEach(btn => btn.onclick = () => {
    state.selectedLeadId = btn.dataset.leadId;
    render();
  });

  const lead = selectedLead();
  if (!lead) {
    $("detailTitle").textContent = "Seleccioná un lead";
    $("detailSub").textContent = "";
    $("leadDetail").innerHTML = `<div class="empty">Elegí un lead para ver la ficha.</div>`;
  } else {
    $("detailTitle").textContent = lead.empresa || "Sin empresa";
    $("detailSub").textContent = `${lead.rubro || ""} · ${lead.provincia || ""}`;
    $("leadDetail").innerHTML = `
      <div class="detail-grid">
        <div class="tip-card"><div class="muted tiny">Teléfono</div><strong>${esc(lead.telefono || "Falta completar")}</strong></div>
        <div class="tip-card"><div class="muted tiny">Contacto</div><strong>${esc(lead.contacto || "Sin dato")}</strong></div>
        <div class="tip-card"><div class="muted tiny">Tamaño</div><strong>${esc(lead.tamano || "Sin dato")}</strong></div>
        <div class="tip-card"><div class="muted tiny">Origen habitual</div><strong>${esc(lead.origen_habitual || "Sin dato")}</strong></div>
      </div>
      <div class="tip-card" style="margin-top:14px"><div class="muted tiny">Siguiente acción</div><strong>${esc(nextAction(lead))}</strong></div>
      <div class="detail-grid" style="margin-top:14px">
        <div><label>Estado</label><select id="detailEstado">${ESTADOS.slice(1).map(o=>`<option value="${esc(o)}" ${lead.estado===o?'selected':''}>${esc(o)}</option>`).join("")}</select></div>
        <div><label>Prioridad</label><select id="detailPrioridad">${PRIORIDADES.map(o=>`<option value="${esc(o)}" ${lead.prioridad===o?'selected':''}>${esc(o)}</option>`).join("")}</select></div>
        <div><label>Último contacto</label><input id="detailUltimo" type="date" value="${esc(lead.ultimo_contacto || "")}"></div>
        <div><label>Próximo seguimiento</label><input id="detailProximo" type="date" value="${esc(lead.proximo_seguimiento || "")}"></div>
      </div>
      <div style="margin-top:14px"><label>Notas</label><textarea id="detailNotas">${esc(lead.notas || "")}</textarea></div>
      <div class="row" style="margin-top:14px">
        <button id="completeLeadBtn" class="btn primary">Completar gestión</button>
        <button id="recontact15Btn" class="btn">Recontacto 15 hábiles</button>
      </div>
    `;
    $("detailEstado").onchange = e => patchLead(lead.id, { estado: e.target.value });
    $("detailPrioridad").onchange = e => patchLead(lead.id, { prioridad: e.target.value });
    $("detailUltimo").onchange = e => patchLead(lead.id, { ultimo_contacto: e.target.value || null });
    $("detailProximo").onchange = e => patchLead(lead.id, { proximo_seguimiento: e.target.value || null });
    $("detailNotas").onchange = e => patchLead(lead.id, { notas: e.target.value });
    $("completeLeadBtn").onclick = () => completeLeadTask(lead.id);
    $("recontact15Btn").onclick = () => patchLead(lead.id, { proximo_seguimiento: addBusinessDays(todayStr(), 15), task_version: (lead.task_version || 1) + 1 });
  }

  const queue = smartQueue();
  $("focusGrid").innerHTML = queue.slice(0,3).map((l,i)=>`
    <div class="focus-card">
      <div class="muted tiny">Focus ${i+1}</div>
      <h3 style="margin-top:8px">${esc(l.empresa)}</h3>
      <div class="muted">${esc(l.rubro)} · ${esc(l.provincia)}</div>
      <div style="margin-top:12px"><strong>Acción:</strong> ${esc(nextAction(l))}</div>
      <div class="row" style="margin-top:14px">
        <button class="btn primary small" onclick="completeLeadTask('${l.id}')">Completar</button>
        <button class="btn small" onclick="openLeadFromOutside('${l.id}')">Abrir</button>
      </div>
    </div>
  `).join("") || `<div class="empty">No hay foco sugerido.</div>`;

  const agendaItems = queue.filter(l => ["vencido","hoy","pronto"].includes(dueLevel(l)) || l.estado === "Nuevo" || !l.telefono).slice(0,20);
  $("agendaList").innerHTML = agendaItems.length ? agendaItems.map((l,i)=>`
    <div class="task-card">
      <div class="row between">
        <div>
          <div class="muted tiny">#${i+1} recomendado</div>
          <strong>${esc(l.empresa)}</strong>
          <div class="muted">${esc(l.rubro)} · ${esc(l.provincia)}</div>
        </div>
        ${dueBadge(l)}
      </div>
      <div style="margin-top:12px"><strong>Motivo:</strong> ${esc(nextAction(l))}</div>
      <div class="row" style="margin-top:14px">
        <button class="btn primary small" onclick="completeLeadTask('${l.id}')">Completar</button>
        <button class="btn small" onclick="openLeadFromOutside('${l.id}')">Abrir</button>
      </div>
    </div>
  `).join("") : `<div class="empty">No hay pendientes en agenda.</div>`;

  $("coachTasksWrap").innerHTML = state.coachTasks.length ? state.coachTasks.map(t=>`
    <div class="tip-card">
      <label class="checkbox-line">
        <input type="checkbox" data-coach-id="${t.id}" ${t.done ? "checked" : ""}>
        <div><strong style="${t.done ? 'text-decoration:line-through;color:#94a3b8' : ''}">${esc(t.title)}</strong><div class="muted tiny" style="margin-top:4px">Objetivo del día</div></div>
      </label>
    </div>
  `).join("") : `<div class="empty">No hay coach cargado hoy.</div>`;
  document.querySelectorAll("[data-coach-id]").forEach(cb => cb.onchange = () => toggleCoachTask(cb.dataset.coachId, cb.checked));

  $("tipsWrap").innerHTML = rotatingTips().map(t => `<div class="tip-card"><strong>Consejo</strong><div class="muted" style="margin-top:6px">${esc(t)}</div></div>`).join("");

  $("taskList").innerHTML = state.tasks.length ? state.tasks.map(t => `
    <div class="task-card">
      <div class="row between">
        <div>
          <strong>${esc(t.title)}</strong>
          <div class="muted tiny" style="margin-top:4px">${esc(t.due_date || "Sin fecha")} · ${t.source === "manual" ? "Manual" : "Gestión"}</div>
        </div>
        <span class="badge">${t.source === "manual" ? "Manual" : "Gestión"}</span>
      </div>
      ${t.notes ? `<div class="muted" style="margin-top:10px">${esc(t.notes)}</div>` : ""}
      <div class="row" style="margin-top:14px">
        <button class="btn ok small" onclick="completeTaskItem('${t.id}')">Completar</button>
        <button class="btn danger small" onclick="deleteTaskItem('${t.id}')">Borrar</button>
      </div>
    </div>
  `).join("") : `<div class="empty">Todavía no hay tareas.</div>`;

  document.querySelectorAll(".bottomnav button").forEach(btn => btn.classList.toggle("active", btn.dataset.tab === state.activeTab));
  ["inicio","leads","agenda","coach","tareas"].forEach(tab => $("tab-"+tab).classList.toggle("hidden", state.activeTab !== tab));
}

function initEvents() {
  $("authPrimaryBtn").onclick = () => state.authMode === "login" ? login() : signup();
  $("authSwitchBtn").onclick = () => switchAuthMode(state.authMode === "login" ? "signup" : "login");
  $("logoutBtn").onclick = logout;
  $("newLeadBtn").onclick = () => openModal("create");
  $("editLeadBtn").onclick = () => { if (selectedLead()) openModal("edit"); };
  $("favLeadBtn").onclick = toggleFavoriteSelected;
  $("deleteLeadBtn").onclick = deleteSelectedLead;
  $("closeModalBtn").onclick = () => $("modalBg").style.display = "none";
  $("cancelModalBtn").onclick = () => $("modalBg").style.display = "none";
  $("saveModalBtn").onclick = saveModal;
  $("importBtn").onclick = () => $("excelInput").click();
  $("excelInput").onchange = (e) => {
    if (e.target.files[0]) importExcel(e.target.files[0]);
    e.target.value = "";
  };
  $("exportBtn").onclick = exportExcel;
  $("notifyBtn").onclick = async () => {
    if (!("Notification" in window)) return showToast("Tu navegador no soporta notificaciones.");
    if (Notification.permission === "granted") {
      new Notification("CRM activo", { body: `Tenés ${metrics().due} seguimientos importantes para hoy.` });
    } else if (Notification.permission !== "denied") {
      const permission = await Notification.requestPermission();
      if (permission === "granted") new Notification("Notificaciones activadas", { body: "Te voy a recordar seguimientos y tareas pendientes." });
    }
  };
  $("searchInput").oninput = (e) => { state.filters.query = e.target.value; window.__metricMode = ""; render(); };
  $("filterProvincia").onchange = (e) => { state.filters.provincia = e.target.value; window.__metricMode = ""; render(); };
  $("filterRubro").onchange = (e) => { state.filters.rubro = e.target.value; window.__metricMode = ""; render(); };
  $("filterEstado").onchange = (e) => { state.filters.estado = e.target.value; window.__metricMode = ""; render(); };
  $("filterPend").onchange = (e) => { state.filters.soloPend = e.target.checked; window.__metricMode = ""; render(); };
  $("filterFav").onchange = (e) => { state.filters.soloFav = e.target.checked; window.__metricMode = ""; render(); };
  document.querySelectorAll(".bottomnav button").forEach(btn => btn.onclick = () => { state.activeTab = btn.dataset.tab; render(); });
  document.querySelectorAll("[data-metric]").forEach(btn => btn.onclick = () => applyMetricFilter(btn.dataset.metric));
  $("createTaskBtn").onclick = createManualTask;
}

async function start() {
  initEvents();
  const { data } = await db.auth.getSession();
  await handleAuth(data.session);
  db.auth.onAuthStateChange(async (_event, session) => {
    await handleAuth(session);
  });
  setInterval(() => {
    if (!state.user) return;
    render();
  }, 60000);
}

start();
